namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();
    private static readonly string[] SampleMessages =
    [
        "Your deployment succeeded.",
        "New comment on PR #42.",
        "Build failed for branch 'main'.",
        "You were mentioned in issue #17.",
        "Security alert: dependency update available.",
        "Pipeline run completed.",
        "New team member joined the project.",
        "Release v2.1.0 published.",
    ];

    public NotificationService()
    {
        // Seed with a few initial notifications.
        for (var i = 0; i < 3; i++)
        {
            _notifications.Add(new Notification(
                _nextId++,
                SampleMessages[i],
                DateTime.UtcNow.AddMinutes(-10 + i)));
        }
    }

    /// <summary>Returns all notifications currently stored.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>Returns notifications created after the given id.</summary>
    public List<Notification> GetSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>
    /// Simulates an external source creating new notifications at random.
    /// Called internally; in a real app this would be an event or message bus.
    /// </summary>
    public void SimulateIncoming()
    {
        if (Random.Shared.Next(0, 3) == 0) // ~33 % chance each tick
        {
            lock (_lock)
            {
                var msg = SampleMessages[Random.Shared.Next(SampleMessages.Length)];
                _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
            }
        }
    }
}

