@page "/notifications"
@rendermode InteractiveServer
@using BlazorNotifications.Services
@inject NotificationService NotificationSvc
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private PersistingComponentStateSubscription _persistSub;

    protected override void OnInitialized()
    {
        // During SSR this persists the data into the page so the interactive
        // runtime can pick it up without a second service call.
        _persistSub = ApplicationState.RegisterOnPersisting(() =>
        {
            ApplicationState.PersistAsJson(nameof(_notifications), _notifications);
            return Task.CompletedTask;
        });

        // On the interactive render, try to restore the persisted data.
        // If not available (first SSR pass), load from the service.
        if (!ApplicationState.TryTakeFromJson<List<Notification>>(
                nameof(_notifications), out var restored))
        {
            _notifications = NotificationSvc.GetAll();
        }
        else
        {
            _notifications = restored!;
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // OnAfterRender only fires on the interactive runtime, never during
        // static SSR, so this is the safe place to start the polling loop.
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }

        await Task.CompletedTask;
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct)
                       .ConfigureAwait(false);

            // Let the service simulate external activity.
            NotificationSvc.SimulateIncoming();

            var lastId = _notifications.Count > 0
                ? _notifications.Max(n => n.Id)
                : 0;

            var newer = NotificationSvc.GetSince(lastId);

            if (newer.Count > 0)
            {
                await InvokeAsync(() =>
                {
                    _notifications.AddRange(newer);
                    StateHasChanged();
                });
            }
        }
    }

    public void Dispose()
    {
        _persistSub.Dispose();
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

